import { f as puedeVerCurso } from "../../../../chunks/authz.js";
import { n as toMoodleErrorMessage } from "../../../../chunks/client.js";
import { t as listarAlumnosDeCurso } from "../../../../chunks/cursos.js";
import { error, redirect } from "@sveltejs/kit";
//#region src/routes/cursos/[id]/+page.server.ts
var load = async ({ params, locals }) => {
	if (!locals.usuario) throw redirect(303, "/auth");
	const cursoId = parseInt(params.id, 10);
	if (isNaN(cursoId)) error(400, "ID de curso invalido");
	if (!await puedeVerCurso(locals.usuario.usuarioId, cursoId)) error(403, "No tenes permiso para ver este curso");
	try {
		return {
			alumnos: await listarAlumnosDeCurso(cursoId),
			cursoId,
			error: null
		};
	} catch (err) {
		return {
			alumnos: [],
			cursoId,
			error: toMoodleErrorMessage(err)
		};
	}
};
//#endregion
export { load };
